Berikut adalah implementasi class `DockerManager` menggunakan `docker-sdk-python` untuk manajemen container yang aman dan terstruktur. Class ini dirancang untuk automasi server dengan penanganan error yang ketat.

### Prerequisites
Install dependencies terlebih dahulu:
```bash
pip install docker
```

### Implementasi Class
```python
import docker
from docker.errors import NotFound, APIError, ContainerError
from typing import List, Optional, Dict

class DockerManager:
    def __init__(self):
        """Inisialisasi koneksi ke Docker Daemon."""
        try:
            self.client = docker.from_env()
            self.client.ping()  # Validasi koneksi
        except docker.errors.DockerException as e:
            raise ConnectionError(f"Gagal terhubung ke Docker Daemon: {str(e)}")

    def list_containers(self, all: bool = False) -> List[Dict]:
        """Mengembalikan daftar container."""
        try:
            containers = self.client.containers.list(all=all)
            return [
                {
                    "id": c.short_id,
                    "name": c.name,
                    "status": c.status,
                    "image": c.image.tags[0] if c.image.tags else "none"
                }
                for c in containers
            ]
        except APIError as e:
            raise RuntimeError(f"API Error saat listing container: {str(e)}")

    def start_container(self, container_id: str) -> bool:
        """Menjalankan container berdasarkan ID atau Nama."""
        try:
            container = self.client.containers.get(container_id)
            container.start()
            return True
        except NotFound:
            raise ValueError(f"Container '{container_id}' tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal memulai container: {str(e)}")

    def stop_container(self, container_id: str, timeout: int = 10) -> bool:
        """Menghentikan container dengan timeout aman."""
        try:
            container = self.client.containers.get(container_id)
            container.stop(timeout=timeout)
            return True
        except NotFound:
            raise ValueError(f"Container '{container_id}' tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menghentikan container: {str(e)}")

    def remove_container(self, container_id: str, force: bool = False) -> bool:
        """Menghapus container. Gunakan force=True hanya jika diperlukan."""
        try:
            container = self.client.containers.get(container_id)
            container.remove(force=force)
            return True
        except NotFound:
            raise ValueError(f"Container '{container_id}' tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menghapus container: {str(e)}")

    def get_logs(self, container_id: str, tail: int = 100) -> str:
        """Mengambil log container untuk audit atau debugging."""
        try:
            container = self.client.containers.get(container_id)
            return container.logs(tail=tail).decode('utf-8')
        except NotFound:
            raise ValueError(f"Container '{container_id}' tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal mengambil log: {str(e)}")

    def exec_command(self, container_id: str, command: List[str]) -> str:
        """Menjalankan command di dalam container. Hindari shell injection."""
        if not isinstance(command, list):
            raise TypeError("Command harus berupa list string untuk keamanan.")

        try:
            container = self.client.containers.get(container_id)
            exec_id = container.exec_run(cmd=command)
            return exec_id.output.decode('utf-8')
        except NotFound:
            raise ValueError(f"Container '{container_id}' tidak ditemukan.")
        except APIError as e:
            raise RuntimeError(f"Gagal menjalankan command: {str(e)}")
```

### Contoh Penggunaan
```python
if __name__ == "__main__":
    try:
        dm = DockerManager()

        # List semua container
        print(dm.list_containers(all=True))

        # Start container
        dm.start_container("web_server_01")

        # Eksekusi command aman
        output = dm.exec_command("web_server_01", ["uname", "-a"])
        print(output)

    except Exception as e:
        print(f"[CRITICAL] {str(e)}")
```

### Catatan Keamanan Penting
1.  **Akses Socket:** User yang menjalankan skrip ini harus memiliki akses ke `/var/run/docker.sock`. Jangan berikan akses ini ke user sembarangan karena setara dengan akses `root` pada host.
2.  **Validasi Input:** Pastikan `container_id` divalidasi sebelum diproses untuk mencegah manipulasi ID.
3.  **Exec Command:** Jangan pernah menggabungkan input user langsung ke dalam command string tanpa sanitasi. Gunakan list argument seperti pada contoh `exec_command` di atas.
4.  **Privilege:** Jalankan aplikasi ini dengan prinsip *least privilege*. Jika tidak butuh akses penuh, batasi via Docker TLS atau socket permissions.

Gunakan class ini untuk integrasi panel manajemen atau automasi deployment yang terkontrol.
